$ProgressPreference = 'SilentlyContinue'; Write-Host 'Downloading test file...'; $url = 'http://speedtest.tele2.net/10MB.zip'; $start = Get-Date; try { $webClient = New-Object System.Net.WebClient; $data = $webClient.DownloadData($url); $end = Get-Date; $duration = ($end - $start).TotalSeconds; $sizeMB = $data.Length / 1MB; $speedMbps = ($sizeMB * 8) / $duration; Write-Host ''; Write-Host 'Download Speed: ' -NoNewline; Write-Host ([math]::Round($speedMbps, 2)) -ForegroundColor Green -NoNewline; Write-Host ' Mbps'; Write-Host 'File Size: ' -NoNewline; Write-Host ([math]::Round($sizeMB, 2)) -NoNewline; Write-Host ' MB'; Write-Host 'Time Taken: ' -NoNewline; Write-Host ([math]::Round($duration, 2)) -NoNewline; Write-Host ' seconds'; } catch { Write-Host 'ERROR: Speed test failed.' -ForegroundColor Red; Write-Host $_.Exception.Message; }
